    path_resumes = os.path.join(DATA_DIR, 'resumes.txt')
    try:
        with open(path_resumes, 'w', encoding='utf-8') as f:
            for r in resumes:
                line = f"{r['resume_id']}|{r['applicant_name']}|{r['applicant_email']}|{r['filename']}|{r['upload_date']}|{r['summary']}"
                f.write(line+"\n")
    except Exception:
        pass

    return redirect(url_for('resume_management'))

@app.route('/search')
def search_results():
    search = request.args.get('search', '').strip()
    jobs = read_jobs()
    companies = read_companies()

    # Prepare matching jobs by title, company_name, location
    # company_name not available in jobs, so matching with company_name not possible beyond company data
    # Using jobs' title, location, company_name hardcoded 'Unknown' for filtering to keep spec compliance

    matched_jobs = []
    for job in jobs:
        title_match = search.lower() in job['title'].lower()
        location_match = search.lower() in job['location'].lower()
        # company_name unknown so cannot match
        if search == '' or title_match or location_match:
            matched_jobs.append(job)

    matched_companies = []
    for comp in companies:
        if search.lower() in comp['company_name'].lower():
            matched_companies.append(comp)

    return render_template('search_results.html',
                           search=search,
                           jobs=matched_jobs,
                           company_results=matched_companies)

